import base64
import os

icons = {
    "home.png": "",
    "home-active.png": "",
    "user.png": "",
    "user-active.png": ""
}

os.makedirs("src/static/tabbar", exist_ok=True)
for name, b64 in icons.items():
    with open(f"src/static/tabbar/{name}", "wb") as f:
        f.write(base64.b64decode(b64))

print("Icons generated successfully.")
